import type { TargetRef } from '../shared/types';
import { stripQuery } from '../shared/util';

function toInt(s: string): number | undefined {
  const n = Number(s);
  return Number.isFinite(n) ? Math.trunc(n) : undefined;
}

/**
 * Best-effort VK target detection from a tab URL. If it returns kind 'unknown'
 * with a screenName, call utils.resolveScreenName to finish resolving.
 */
export function detectTargetFromUrl(rawUrl: string): TargetRef {
  const url = stripQuery(rawUrl);
  let u: URL | null = null;
  try { u = new URL(url); } catch { /* ignore */ }
  const path = (u ? u.pathname : url).replace(/^\/+/, '');
  const first = path.split('/')[0] || '';
  const target: TargetRef = { kind: 'unknown', url };

  // e.g. vk.com/id123
  if (/^id\d+$/.test(first)) {
    target.kind = 'user';
    target.id = toInt(first.slice(2));
    return target;
  }

  // e.g. vk.com/club123 or vk.com/public123
  if (/^(club|public)\d+$/.test(first)) {
    target.kind = 'group';
    target.id = toInt(first.replace(/^(club|public)/, ''));
    return target;
  }

  // e.g. vk.com/wall123_456 or vk.com/wall-123_456
  if (/^wall-?\d+_\d+$/.test(first)) {
    const m = first.match(/^wall(-?\d+)_/);
    const owner = m ? toInt(m[1]) : undefined;
    target.ownerId = owner;
    if (typeof owner === 'number') {
      if (owner < 0) {
        target.kind = 'group';
        target.id = Math.abs(owner);
      } else {
        target.kind = 'user';
        target.id = owner;
      }
    }
    return target;
  }

  // Some pages use /video123_456, /photo123_456, etc.
  if (/^(video|photo|topic)-?\d+_\d+/.test(first)) {
    const m = first.match(/^(?:video|photo|topic)(-?\d+)_/);
    const owner = m ? toInt(m[1]) : undefined;
    target.ownerId = owner;
    if (typeof owner === 'number') {
      if (owner < 0) {
        target.kind = 'group';
        target.id = Math.abs(owner);
      } else {
        target.kind = 'user';
        target.id = owner;
      }
    }
    return target;
  }

  // e.g. vk.com/durov
  if (first && /^[A-Za-z0-9_.]{3,}$/.test(first)) {
    target.kind = 'unknown';
    target.screenName = first;
    return target;
  }

  return target;
}
