import type { ExtractionRun, TargetRef, VkXtractBundle, VkXtractStats } from '../shared/types';
import { now } from '../shared/util';

// Token remains in chrome.storage.local (simple UX)
const TOKEN_KEY = 'vkx_token';

// Active "case" key (derived automatically):
// user => "123"  |  group => "-123" (VK standard)
const ACTIVE_CASE_KEY = 'vkx_active_case';

// IndexedDB storage (one DB, many targets)
const DB_NAME = 'vkxtract';
const DB_VERSION = 1;
const STORE_BUNDLES = 'bundles';

type BundleRecord = { key: string; bundle: VkXtractBundle };

let dbPromise: Promise<IDBDatabase> | null = null;

function openDb(): Promise<IDBDatabase> {
  if (dbPromise) return dbPromise;
  dbPromise = new Promise((resolve, reject) => {
    const req = indexedDB.open(DB_NAME, DB_VERSION);
    req.onerror = () => reject(req.error);
    req.onupgradeneeded = () => {
      const db = req.result;
      if (!db.objectStoreNames.contains(STORE_BUNDLES)) {
        db.createObjectStore(STORE_BUNDLES, { keyPath: 'key' });
      }
    };
    req.onsuccess = () => resolve(req.result);
  });
  return dbPromise;
}

function idbGet<T>(db: IDBDatabase, store: string, key: IDBValidKey): Promise<T | undefined> {
  return new Promise((resolve, reject) => {
    const tx = db.transaction(store, 'readonly');
    const st = tx.objectStore(store);
    const req = st.get(key);
    req.onerror = () => reject(req.error);
    req.onsuccess = () => resolve(req.result as T | undefined);
  });
}

function idbPut<T>(db: IDBDatabase, store: string, value: T): Promise<void> {
  return new Promise((resolve, reject) => {
    const tx = db.transaction(store, 'readwrite');
    const st = tx.objectStore(store);
    const req = st.put(value as any);
    req.onerror = () => reject(req.error);
    req.onsuccess = () => resolve();
  });
}

function idbDelete(db: IDBDatabase, store: string, key: IDBValidKey): Promise<void> {
  return new Promise((resolve, reject) => {
    const tx = db.transaction(store, 'readwrite');
    const st = tx.objectStore(store);
    const req = st.delete(key);
    req.onerror = () => reject(req.error);
    req.onsuccess = () => resolve();
  });
}

function idbClear(db: IDBDatabase, store: string): Promise<void> {
  return new Promise((resolve, reject) => {
    const tx = db.transaction(store, 'readwrite');
    const st = tx.objectStore(store);
    const req = st.clear();
    req.onerror = () => reject(req.error);
    req.onsuccess = () => resolve();
  });
}

function emptyBundle(target?: TargetRef): VkXtractBundle {
  return {
    schema: 'vkxtract.capture.v1',
    createdAt: now(),
    lastUpdatedAt: now(),
    lastPageUrl: undefined,
    target: target || { kind: 'unknown' },
    runs: []
  };
}

function caseKeyFromTarget(t: TargetRef | undefined | null): string {
  if (!t) return 'unknown';

  const owner = typeof t.ownerId === 'number'
    ? t.ownerId
    : (t.kind === 'group' && typeof t.id === 'number')
      ? -Math.abs(t.id)
      : (t.kind === 'user' && typeof t.id === 'number')
        ? t.id
        : undefined;

  if (typeof owner === 'number' && Number.isFinite(owner) && owner !== 0) return String(owner);

  // IMPORTANT: for unresolved screen_name targets (token missing/invalid), keep a stable per-target key.
  const sn = (t.screenName && String(t.screenName).trim()) ? String(t.screenName).trim().toLowerCase() : '';
  if (sn) return `sn:${sn}`;

  return 'unknown';
}

async function getActiveCaseKey(): Promise<string> {
  const r = await chrome.storage.local.get({ [ACTIVE_CASE_KEY]: 'unknown' });
  return String(r[ACTIVE_CASE_KEY] || 'unknown');
}

async function setActiveCaseKey(key: string): Promise<void> {
  await chrome.storage.local.set({ [ACTIVE_CASE_KEY]: key || 'unknown' });
}

async function loadBundleByKey(key: string): Promise<VkXtractBundle> {
  const db = await openDb();
  const rec = await idbGet<BundleRecord>(db, STORE_BUNDLES, key);
  const b = rec?.bundle;
  if (b && b.schema === 'vkxtract.capture.v1' && Array.isArray(b.runs)) return b;
  const fresh = emptyBundle();
  await idbPut(db, STORE_BUNDLES, { key, bundle: fresh } as BundleRecord);
  return fresh;
}

async function saveBundleByKey(key: string, bundle: VkXtractBundle): Promise<void> {
  const db = await openDb();
  await idbPut(db, STORE_BUNDLES, { key, bundle } as BundleRecord);
}

// Actions for which we keep only the latest run (reduces bundle growth over time)
const REPLACE_ACTIONS = new Set<string>([
  'users.get',
  'groups.getById',
  'friends.get',
  'groups.getMembers',
  'users.getSubscriptions',
  'groups.get',
  'photos.getAll',
  'photos.get',
  'photos.getAlbums',
  'video.get',
  'video.getAlbums',
  'stories.get',
  'database.getCitiesById',
  'users.get_related',
  'users.get_engagement_top_photos',
  'users.get_engagement_top_videos',
  'vkx.photos.enrich',
  'vkx.videos.enrich',
  'vkx.users.resolve',
  'gifts.get',
  'users.get_gifts_senders'
]);

export async function getToken(): Promise<string> {
  const r = await chrome.storage.local.get({ [TOKEN_KEY]: '' });
  return String(r[TOKEN_KEY] || '');
}

export async function setToken(token: string): Promise<void> {
  await chrome.storage.local.set({ [TOKEN_KEY]: token || '' });
}

export async function clearToken(): Promise<void> {
  await chrome.storage.local.set({ [TOKEN_KEY]: '' });
}

export async function loadBundle(): Promise<VkXtractBundle> {
  const key = await getActiveCaseKey();
  return await loadBundleByKey(key);
}

export async function saveBundle(bundle: VkXtractBundle): Promise<void> {
  const key = caseKeyFromTarget(bundle?.target);
  await setActiveCaseKey(key);
  await saveBundleByKey(key, bundle);
}

export async function resetBundle(): Promise<VkXtractBundle> {
  const key = await getActiveCaseKey();
  const fresh = emptyBundle();
  await saveBundleByKey(key, fresh);
  return fresh;
}

export async function updateTarget(next: TargetRef, pageUrl?: string): Promise<VkXtractBundle> {
  const key = caseKeyFromTarget(next);
  await setActiveCaseKey(key);
  const b = await loadBundleByKey(key);
  b.target = next;
  if (pageUrl) b.lastPageUrl = pageUrl;
  b.lastUpdatedAt = now();
  await saveBundleByKey(key, b);
  return b;
}

export async function addRun(run: ExtractionRun, pageUrl?: string): Promise<VkXtractBundle> {
  const key = caseKeyFromTarget(run?.target);
  await setActiveCaseKey(key);
  const b = await loadBundleByKey(key);

  if (REPLACE_ACTIONS.has(run.action)) {
    for (let i = b.runs.length - 1; i >= 0; i--) {
      if (b.runs[i]?.action === run.action) {
        b.runs[i] = run;
        b.lastUpdatedAt = now();
        if (pageUrl) b.lastPageUrl = pageUrl;
        b.target = run.target || b.target;
        await saveBundleByKey(key, b);
        return b;
      }
    }
  }

  b.runs.push(run);
  b.lastUpdatedAt = now();
  if (pageUrl) b.lastPageUrl = pageUrl;
  b.target = run.target || b.target;
  await saveBundleByKey(key, b);
  return b;
}

export async function getStats(): Promise<VkXtractStats> {
  const token = await getToken();
  const activeCaseKey = await getActiveCaseKey();

  let b: VkXtractBundle;
  if (activeCaseKey && activeCaseKey !== 'unknown') {
    b = await loadBundleByKey(activeCaseKey);
  } else {
    b = emptyBundle();
  }

  const last = b.runs.length ? b.runs[b.runs.length - 1] : undefined;

  const tokenTrimmed = String(token || '').trim();
  const tokenMask = tokenTrimmed
    ? `••••${tokenTrimmed.slice(-6)}`
    : undefined;

  return {
    tokenSet: !!tokenTrimmed,
    tokenMask,
    activeCaseKey,
    target: b.target,
    runs: b.runs.length,
    lastAction: last ? `${last.action} • ${new Date(last.ts).toLocaleTimeString()}` : undefined
  };
}

export async function exportBundle(): Promise<VkXtractBundle> {
  return await loadBundle();
}

// Storage management helpers
export async function deleteActiveTargetData(): Promise<void> {
  const key = await getActiveCaseKey();
  const db = await openDb();
  await idbDelete(db, STORE_BUNDLES, key);
  await setActiveCaseKey('unknown');
}

export async function deleteTargetData(key: string): Promise<void> {
  const k = String(key || '').trim();
  if (!k) return;
  const db = await openDb();
  await idbDelete(db, STORE_BUNDLES, k);
  const active = await getActiveCaseKey();
  if (active === k) await setActiveCaseKey('unknown');
}

export async function deleteAllData(): Promise<void> {
  const db = await openDb();
  await idbClear(db, STORE_BUNDLES);
  await setActiveCaseKey('unknown');
}

function pickProfileLabel(b: VkXtractBundle): { label?: string; photo?: string } {
  try {
    const t = b?.target;
    // Find the most useful profile run.
    const run = (b?.runs || []).find((r) => r?.action === 'users.get')
      || (b?.runs || []).find((r) => r?.action === 'groups.getById');
    const resp = run?.response;

    if (t?.kind === 'user' && Array.isArray(resp) && resp[0]) {
      const u: any = resp[0];
      const label = [u.first_name, u.last_name].filter(Boolean).join(' ').trim()
        || String(u.domain || '')
        || (typeof t.id === 'number' ? String(t.id) : undefined);
      const photo = String(u.photo_100 || u.photo_50 || u.photo_200 || '') || undefined;
      return { label: label || undefined, photo };
    }
    if (t?.kind === 'group' && Array.isArray(resp) && resp[0]) {
      const g: any = resp[0];
      const label = String(g.name || g.screen_name || '') || (typeof t.id === 'number' ? `-${t.id}` : undefined);
      const photo = String(g.photo_100 || g.photo_200 || '') || undefined;
      return { label: label || undefined, photo };
    }
  } catch {
    // ignore
  }
  return {};
}

function approxBytesOfBundle(b: VkXtractBundle): number {
  try {
    const str = JSON.stringify(b);
    // TextEncoder exists in modern MV3 service workers.
    return new TextEncoder().encode(str).length;
  } catch {
    return 0;
  }
}

export type StorageTargetSummary = {
  key: string;
  kind: TargetRef['kind'];
  label: string;
  photo?: string;
  lastUpdatedAt: number;
  runs: number;
  approxBytes: number;
};

export async function listStoredTargets(limit = 50): Promise<{ items: StorageTargetSummary[]; totalBytes: number; totalTargets: number }> {
  const db = await openDb();
  const items: StorageTargetSummary[] = [];
  let totalBytes = 0;
  let totalTargets = 0;

  await new Promise<void>((resolve, reject) => {
    const tx = db.transaction(STORE_BUNDLES, 'readonly');
    const st = tx.objectStore(STORE_BUNDLES);
    const req = st.openCursor();
    req.onerror = () => reject(req.error);
    req.onsuccess = () => {
      const cur = req.result as IDBCursorWithValue | null;
      if (!cur) {
        resolve();
        return;
      }

      const rec = cur.value as BundleRecord;
      const key = String(rec?.key ?? '');
      const b = rec?.bundle;
      if (key && b && b.schema === 'vkxtract.capture.v1') {
        const runsCount = Array.isArray(b.runs) ? b.runs.length : 0;
        const isEmptyUnknown = key === 'unknown' && (b.target?.kind || 'unknown') === 'unknown' && runsCount === 0;
        if (!isEmptyUnknown) {
          totalTargets += 1;
          const ab = approxBytesOfBundle(b);
          totalBytes += ab;
          const meta = pickProfileLabel(b);
          const label = meta.label
            || (b.target?.screenName ? String(b.target.screenName) : '')
            || key;
          items.push({
            key,
            kind: b.target?.kind || 'unknown',
            label,
            photo: meta.photo,
            lastUpdatedAt: Number(b.lastUpdatedAt || b.createdAt || 0),
            runs: runsCount,
            approxBytes: ab
          });
        }
      }
      cur.continue();
    };
  });

  items.sort((a, b) => (b.lastUpdatedAt || 0) - (a.lastUpdatedAt || 0));
  const sliced = items.slice(0, Math.max(1, Math.min(200, Number(limit) || 50)));
  return { items: sliced, totalBytes, totalTargets };
}
export async function findStoredTargetByScreenName(screenName: string): Promise<{ key: string; target: TargetRef } | null> {
  const sn = String(screenName || '').trim().toLowerCase();
  if (!sn) return null;

  const db = await openDb();

  return await new Promise((resolve, reject) => {
    const tx = db.transaction(STORE_BUNDLES, 'readonly');
    const st = tx.objectStore(STORE_BUNDLES);
    const req = st.openCursor();

    req.onerror = () => reject(req.error);
    req.onsuccess = () => {
      const cur = req.result as IDBCursorWithValue | null;
      if (!cur) {
        resolve(null);
        return;
      }

      const rec = cur.value as BundleRecord;
      const key = String(rec?.key ?? '');
      const b = rec?.bundle as VkXtractBundle | undefined;

      try {
        const t = b?.target;

        const tSn = (t?.screenName && String(t.screenName).trim()) ? String(t.screenName).trim().toLowerCase() : '';
        if (tSn && tSn === sn && t) {
          resolve({ key, target: t });
          return;
        }

        // Also match against the resolved domain/screen_name inside stored profile responses.
        const runs = Array.isArray(b?.runs) ? b!.runs : [];
        const prof = runs.find((r) => r?.action === 'users.get') || runs.find((r) => r?.action === 'groups.getById');
        const resp0 = Array.isArray(prof?.response) ? (prof!.response as any[])[0] : null;

        const cand = resp0 ? String(resp0.domain || resp0.screen_name || '').trim().toLowerCase() : '';
        if (cand && cand === sn && t) {
          resolve({ key, target: t });
          return;
        }
      } catch {
        // ignore
      }

      cur.continue();
    };
  });
}